/**
 * Builds filter clauses from validated filter parameters.
 */
function buildFilters(filters) {
  const filterClauses = [];

  for (const filter of filters) {
    if (!validateFieldName(filter.field)) {
      throw new Error(`Invalid filter field name: ${filter.field}`);
    }

    switch (filter.type) {
      case 'term':
        filterClauses.push({ term: { [filter.field]: filter.value } });
        break;
      case 'terms':
        if (!Array.isArray(filter.value)) {
          throw new Error(`Terms filter requires an array value for field: ${filter.field}`);
        }
        filterClauses.push({ terms: { [filter.field]: filter.value } });
        break;
      case 'range':
        if (typeof filter.value !== 'object' || Array.isArray(filter.value)) {
          throw new Error(`Range filter requires an object value for field: ${filter.field}`);
        }
        filterClauses.push({ range: { [filter.field]: filter.value } });
        break;
      case 'exists':
        filterClauses.push({ exists: { field: filter.field } });
        break;
      default:
        throw new Error(`Unsupported filter type: ${filter.type}`);
    }
  }

  return filterClauses;
}

/**
 * Builds the complete Elasticsearch query from validated parameters.
 */
function buildSearchQuery(params) {
  // Build the base multi_match query
  const baseQuery = {
    bool: {
      must: [
        {
          multi_match: {
            query: params.query,
            fields: params.fields,
            type: 'best_fields',
            fuzziness: 'AUTO'
          }
        }
      ],
      filter: []
    }
  };

  // Add filters
  if (params.filters && params.filters.length > 0) {
    baseQuery.bool.filter = buildFilters(params.filters);
  }

  // Apply scoring if provided
  let finalQuery;
  if (params.scoring) {
    finalQuery = buildScoringQuery(baseQuery, params.scoring);
  } else {
    finalQuery = baseQuery;
  }

  // Build the complete search body
  const searchBody = {
    query: finalQuery,
    from: (params.pagination.page - 1) * params.pagination.size,
    size: params.pagination.size
  };

  // Add sorting
  if (params.sort && params.sort.length > 0) {
    searchBody.sort = params.sort.map(s => {
      if (!validateFieldName(s.field)) {
        throw new Error(`Invalid sort field name: ${s.field}`);
      }
      return { [s.field]: { order: s.order } };
    });
    // Always add _score as secondary sort
    searchBody.sort.push({ _score: { order: 'desc' } });
  }

  // Add highlighting
  if (params.highlight) {
    searchBody.highlight = {
      fields: {},
      pre_tags: ['<mark>'],
      post_tags: ['</mark>'],
      fragment_size: 150,
      number_of_fragments: 3
    };
    for (const field of params.fields) {
      if (validateFieldName(field)) {
        searchBody.highlight.fields[field] = {};
      }
    }
  }

  return searchBody;
}

// Main search endpoint
app.post('/api/search', async (req, res) => {
  try {
    // Validate input using Joi schema
    const { error, value: params } = searchParamsSchema.validate(req.body, {
      abortEarly: false,
      stripUnknown: true
    });

    if (error) {
      return res.status(400).json({
        error: 'Validation error',
        details: error.details.map(d => ({
          message: d.message,
          path: d.path.join('.')
        }))
      });
    }

    // Build the search query
    const searchBody = buildSearchQuery(params);

    // Execute the search
    const result = await esClient.search({
      index: params.index,
      body: searchBody
    });

    // Format response
    const response = {
      total: typeof result.hits.total === 'object' ? result.hits.total.value : result.hits.total,
      page: params.pagination.page,
      size: params.pagination.size,
      took: result.took,
      hits: result.hits.hits.map(hit => ({
        id: hit._id,
        score: hit._score,
        source: hit._source,
        highlight: hit.highlight || null
      }))
    };

    res.json(response);
  } catch (err) {
    console.error('Search error:', err.message);

    if (err.meta && err.meta.statusCode) {
      return res.status(err.meta.statusCode).json({
        error: 'Elasticsearch error',
        message: 'An error occurred while processing your search request'
      });
    }

    res.status(400).json({
      error: 'Search error',
      message: err.message
    });
  }
});

